export function guidesFor(match) {
  const m = match.toLowerCase();
  return guides.filter((g) => g.cats.toLowerCase().includes(m));
}

// ── Locale helpers (fallback to EN) ──
export function guideTitle(g, lang) {
  return (lang !== 'en' && g[`title_${lang}`]) || g.title;
}
export function guideDek(g, lang) {
  return (lang !== 'en' && g[`dek_${lang}`]) || g.dek;
}
export function guideHref(g, lang) {
  return localized(g.href, lang);
}
export function catLabel(c, lang) {
  return (lang !== 'en' && c[`label_${lang}`]) || c.label;
}

// Temps de lecture localisé : g.read = "6 min read" → "6 min de lecture" / "6 min de lectura".
const READ_UNIT = { en: 'min read', fr: 'min de lecture', es: 'min de lectura', de: 'Min. Lesezeit', it: 'min di lettura', pt: 'min de leitura' };
export function guideRead(g, lang) {
  const n = (String(g.read).match(/\d+/) || ['1'])[0];
  return `${n} ${READ_UNIT[lang] || READ_UNIT.en}`;
}

// Noms de catégories des cartes (g.cats = "Programming, Concepts") traduits par mot.
// catAvatar() doit continuer à recevoir g.cats EN (matching) - n'utiliser guideCats que pour l'AFFICHAGE.
const CAT_TR = {
  fr: { Programming: 'Programmation', Concepts: 'Concepts', Data: 'Données', Databases: 'Bases de données', Tools: 'Outils', Workflow: 'Workflow', Web: 'Web', Haskell: 'Haskell', Build: 'Build', Syntax: 'Syntaxe', Compiler: 'Compilateur', Editor: 'Éditeur', Toolchain: 'Chaîne d’outils', Performance: 'Performance', Cabal: 'Cabal' },
  es: { Programming: 'Programación', Concepts: 'Conceptos', Data: 'Datos', Databases: 'Bases de datos', Tools: 'Herramientas', Workflow: 'Flujo de trabajo', Web: 'Web', Haskell: 'Haskell', Build: 'Compilación', Syntax: 'Sintaxis', Compiler: 'Compilador', Editor: 'Editor', Toolchain: 'Cadena de herramientas', Performance: 'Rendimiento', Cabal: 'Cabal' },
  de: { Programming: 'Programmierung', Concepts: 'Konzepte', Data: 'Daten', Databases: 'Datenbanken', Tools: 'Werkzeuge', Workflow: 'Workflow', Web: 'Web', Haskell: 'Haskell', Build: 'Build', Syntax: 'Syntax', Compiler: 'Compiler', Editor: 'Editor', Toolchain: 'Toolchain', Performance: 'Performance', Cabal: 'Cabal' },
  it: { Programming: 'Programmazione', Concepts: 'Concetti', Data: 'Dati', Databases: 'Database', Tools: 'Strumenti', Workflow: 'Flusso di lavoro', Web: 'Web', Haskell: 'Haskell', Build: 'Build', Syntax: 'Sintassi', Compiler: 'Compilatore', Editor: 'Editor', Toolchain: 'Toolchain', Performance: 'Prestazioni', Cabal: 'Cabal' },
  pt: { Programming: 'Programação', Concepts: 'Conceitos', Data: 'Dados', Databases: 'Bases de dados', Tools: 'Ferramentas', Workflow: 'Fluxo de trabalho', Web: 'Web', Haskell: 'Haskell', Build: 'Build', Syntax: 'Sintaxe', Compiler: 'Compilador', Editor: 'Editor', Toolchain: 'Toolchain', Performance: 'Desempenho', Cabal: 'Cabal' },
};
export function guideCats(g, lang) {
  const map = CAT_TR[lang];
  if (!map) return g.cats;
  return String(g.cats).split(',').map((c) => { const k = c.trim(); return map[k] || k; }).join(', ');
}
